SELECT survey_id
FROM responses
WHERE response_category = 1 AND percentage = (SELECT MAX(percentage) FROM responses WHERE response_category = 1);

SELECT category_name
FROM response_categories
WHERE category_id = 0;

SELECT COUNT(response_id) AS total_responses
FROM responses
WHERE survey_id = 1;

SELECT percentage
FROM responses
WHERE response_id = 1;

SELECT COUNT(participant_id) AS total_participants
FROM participants
WHERE survey_id = 1;

SELECT COUNT(*) 
FROM participants 
WHERE survey_id = 1;
